INSERT INTO `reviews` (`id`, `user_id`, `business_id`, `rating`, `comment`, `created_at`, `updated_at`) VALUES
(1, 11, 1, 5, 'Burgerler harikaydı! Özellikle special burger çok lezzetli. Kesinlikle tekrar geleceğim.', '2026-01-06 12:58:04', '2026-01-06 12:58:04'),
(2, 12, 1, 4, 'Güzel bir mekan, fiyatlar biraz yüksek ama kalite gerçekten iyi.', '2026-01-06 12:58:04', '2026-01-06 12:58:04'),
(3, 11, 2, 5, 'Ev yemekleri çok lezzetli, annemin yemeklerini hatırlattı. Porsiyon da gayet bol.', '2026-01-06 12:58:04', '2026-01-06 12:58:04'),
(4, 13, 2, 5, 'Ankara\'nın en iyi restoranlarından biri. Her şey çok taze ve lezzetli.', '2026-01-06 12:58:04', '2026-01-06 12:58:04'),
(5, 12, 4, 4, 'Kahveleri gerçekten çok iyi, pastalar taze. Atmosfer harika.', '2026-01-06 12:58:04', '2026-01-06 12:58:04'),
(6, 11, 6, 5, 'Profesyonel ekip, harika sonuç. Düğün öncesi hazırlık için mükemmeldi!', '2026-01-06 12:58:04', '2026-01-06 12:58:04');
